/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ProdParameters, GridKPMGCommon_AutomaticOrderCreationParameters_ItemId), FormControlEventType::Lookup)]
public static void GridKPMGCommon_AutomaticOrderCreationParameters_ItemId_OnLookup(FormControl sender, FormControlEventArgs e)
{
    InventTable::lookupFormulaItemId(sender);
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ProdParameters, GridKPMGCommon_AutomaticOrderCreationParameters_FormulaId), FormControlEventType::Lookup)]
public static void GridKPMGCommon_AutomaticOrderCreationParameters_FormulaId_OnLookup(FormControl sender, FormControlEventArgs e)
{
    KPMGCommon_AutomaticOrderCreationParameters automaticOrderCreationParameters = sender.dataSourceObject().cursor();
    InventTable                                 inventTable = InventTable::find(automaticOrderCreationParameters.itemId);
    InventDim                                   inventDim;

    inventDim.initFromInventTable(inventTable,
                                  InventItemOrderSetupType::Invent,
                                  null);

    if (inventTable.isFormulaAllowed())
    {
        InventTable::lookupFormulaId(sender, automaticOrderCreationParameters.ItemId,inventDim);
    }
    else
    {
        InventTable::lookupBOMId(sender, automaticOrderCreationParameters.ItemId, inventDim, true, false);
    }
}

