[FormControlEventHandler(formControlStr(ProdParameters, GridKPMGCommon_AutomaticOrderCreationParameters_RouteId), FormControlEventType::Lookup)]
public static void GridKPMGCommon_AutomaticOrderCreationParameters_RouteId_OnLookup(FormControl sender, FormControlEventArgs e)
{
    KPMGCommon_AutomaticOrderCreationParameters automaticOrderCreationParameters = sender.dataSourceObject().cursor();
    InventTable                                 inventTable = InventTable::find(automaticOrderCreationParameters.itemId);
    InventDim                                   inventDim;

    inventDim.initFromInventTable(inventTable,
                                InventItemOrderSetupType::Invent,
                                null);

    InventTable::lookupRouteId(sender, automaticOrderCreationParameters.ItemId, inventDim, true, false);

}
